            with open(f, 'r') as file:
                data = json.load(file)
                print(f'\nSuccessfully loaded civic data from {f}')
                print(f'  Records: {len(data)}')
                # Show first record keys
                if data:
                    print(f'  Keys: {list(data[0].keys())}')
                break
        except:
            continue

# Try to read funding data
